INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '310701df-99d6-46db-9a20-b7dd68d95d1d',
  '00000000-0000-0000-0000-000000000001',
  $escape$SvelteKit SSG vs SSR vs ISR — Decision Matrix and Parallel Loader Performance$escape$,
  $escape$SvelteKit's rendering mode is controlled by exports in `+page.ts` or `+page.server.ts`, not config files. Use `export const prerender = true` for SSG — correct for docs, marketing, or any route with zero per-request variance. Default SSR runs your `load` on every request; keep it for auth-gated, personalized, or real-time pages. ISR isn't native to SvelteKit's core, but `adapter-vercel` exposes `export const config = { isr: { expiration: 60 } }` per-route for edge revalidation. For self-hosted deploys, set `Cache-Control: stale-while-revalidate` in your `handle` hook instead.

The highest-yield SSR optimization is eliminating waterfall fetches inside `load`. SvelteKit lets you return unawaited promises — the runtime streams them to the client, enabling `{#await}` blocks to resolve independently. For server-only parallel fetches, use `Promise.all` over SvelteKit's injected `fetch`, not `globalThis.fetch`. The injected version forwards cookies automatically, deduplicates identical requests within the same render cycle, and resolves relative URLs against the origin — none of which global fetch does in a Node SSR context.$escape$,
  $escape$// +page.server.ts
import type { PageServerLoad } from './$types';

// SSG: export const prerender = true;
// ISR (Vercel only): export const config = { isr: { expiration: 60 } };

export const load: PageServerLoad = async ({ fetch }) => {
  // Return promises unresolved — SvelteKit streams each independently
  return {
    posts:    fetch('/api/posts').then(r => r.json()),
    trending: fetch('/api/trending').then(r => r.json()),
  };
};$escape$,
  $escape$typescript$escape$,
