INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ac6fcf29-758a-4c49-a48b-a9605a46b457',
  '00000000-0000-0000-0000-000000000001',
  $escape$SvelteKit Forms — Server Actions, Progressive Enhancement, and Server-Side Validation$escape$,
  $escape$SvelteKit's form actions run exclusively on the server via the `actions` export in `+page.server.ts`. Your `<form>` POSTs to the same route by default — no `fetch`, no API endpoint needed. Validation happens in the action using `request.formData()`, and failures are returned with `fail(422, { errors })`, which SvelteKit sends back as `ActionData`. Bind it in `+page.svelte` via the `form` prop (typed as `ActionData`). This works with zero JavaScript — true progressive enhancement. Add `use:enhance` from `$app/forms` to intercept the submission client-side, skip the full-page reload, and still receive the same `ActionData` back. The `enhance` callback gives you fine-grained control: optimistic UI, custom loading states, or preventing the default update entirely. Crucially, `fail()` sets the HTTP status without throwing, so SvelteKit keeps the form data in scope for re-population. Never use `throw redirect()` on validation failure — that drops the error payload. Server actions also automatically protect against CSRF via SvelteKit's built-in origin check, so form submissions from foreign origins are rejected without any extra middleware.$escape$,
  $escape$// +page.server.ts
import { fail } from '@sveltejs/kit';
import type { Actions } from './$types';

export const actions: Actions = {
  default: async ({ request }) => {
    const data = await request.formData();
    const email = data.get('email')?.toString().trim();

    if (!email || !email.includes('@')) {
      return fail(422, { email, errors: { email: 'Valid email required' } });
    }

    await subscribeUser(email);
  }
};

// +page.svelte
<script lang="ts">
  import { enhance } from '$app/forms';
  import type { ActionData } from './$types';
  let { form }: { form: ActionData } = $props();
</script>

<form method="POST" use:enhance>
  <input name="email" value={form?.email ?? ''} />
  {#if form?.errors?.email}<p>{form.errors.email}</p>{/if}
  <button>Subscribe</button>
</form>$escape$,
  $escape$typescript$escape$,
