INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4a5065d9-361c-4dd6-af3f-572b17f0f10c',
  '00000000-0000-0000-0000-000000000001',
  $escape$SvelteKit — Typed Route Params, Loaders, and Search Params with Zod$escape$,
  $escape$SvelteKit's generated `$types` module gives you `PageLoad`, `PageServerLoad`, and `RouteParams` — but these are structural types, not validated at runtime. Combine them with Zod to get both compile-time safety and runtime validation in a single pass.

In `+page.server.ts`, destructure `params` typed via `PageServerLoad` and parse with a Zod schema. For search params, SvelteKit passes them through `url.searchParams` — not typed by default. Zod's `z.coerce` handles the string-to-number conversion that `URLSearchParams` always returns.

The key SvelteKit-specific detail: `load` functions run both on the server and client during SSR hydration. A Zod `safeParse` lets you throw a `redirect` or `error` (from `@sveltejs/kit`) cleanly inside `load` without leaking stack traces to the client. Typed returns from `load` flow into `+page.svelte` via the `data` prop, which `PageData` narrows automatically — no casting needed downstream.$escape$,
  $escape$// src/routes/tools/[slug]/+page.server.ts
import { error } from '@sveltejs/kit';
import { z } from 'zod';
import type { PageServerLoad } from './$types';

const paramsSchema = z.object({ slug: z.string().min(1) });
const searchSchema = z.object({
  page: z.coerce.number().int().positive().default(1),
  q: z.string().optional(),
});

export const load: PageServerLoad = ({ params, url }) => {
  const { slug } = paramsSchema.parse(params);
  const search = searchSchema.safeParse(
    Object.fromEntries(url.searchParams)
  );
  if (!search.success) throw error(400, 'Invalid query params');
  return { slug, ...search.data };
};$escape$,
  $escape$typescript$escape$,
