INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9905cf25-d84d-4a74-9c34-fef84cc26f16',
  '00000000-0000-0000-0000-000000000001',
  $escape$SvelteKit Route Conventions — Consistent Naming for Loaders and Actions$escape$,
  $escape$SvelteKit's file-based routing gives you `+page.server.ts`, `+layout.server.ts`, and `+server.ts` — but code quality degrades fast when teams name exported functions inconsistently. The convention: always name your `load` function `load` and your form actions descriptively, never default.

In `+page.server.ts`, export a named `load` function (typed with `PageServerLoad`) and a named `actions` object with verb-first keys like `create`, `update`, or `deletePost`. This makes `$page.form` errors traceable and `use:enhance` bindings explicit.

Avoid exporting anonymous arrow functions as `load` — type inference breaks and stack traces become unreadable. For `+layout.server.ts`, prefix shared data keys with the layout segment name (e.g., `dashboardUser`) to prevent key collisions when layout and page `load` data are merged into `$page.data`.

Use `satisfies` instead of `as` for typing `actions` — it preserves the literal action keys so `ActionResult` generics resolve correctly downstream in your `+page.svelte` `ActionData` type.$escape$,
  $escape$// src/routes/dashboard/posts/+page.server.ts
import type { PageServerLoad, Actions } from './$types';

export const load = (async ({ locals }) => {
  const posts = await locals.db.post.findMany();
  return { posts };
}) satisfies PageServerLoad;

export const actions = {
  create: async ({ request, locals }) => {
    const data = await request.formData();
    await locals.db.post.create({ data: { title: String(data.get('title')) } });
  },
  deletePost: async ({ request, locals }) => {
    const id = String((await request.formData()).get('id'));
    await locals.db.post.delete({ where: { id } });
  }
} satisfies Actions;$escape$,
  $escape$typescript$escape$,
