INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '896c3304-89e1-4a55-a0c3-708625b2a8a5',
  '00000000-0000-0000-0000-000000000001',
  $escape$SvelteKit Routing Deep Dive — Dynamic Segments, Catch-Alls, and Groups$escape$,
  $escape$SvelteKit's filesystem router maps `src/routes` to URLs with zero config. A folder named `[slug]` creates a dynamic segment — accessible via `params.slug` in both `+page.svelte` and `+page.server.ts` load functions. Wrap a segment in `[[optional]]` to make it optional without creating a separate route.

Catch-all routes use `[...rest]` — `src/routes/docs/[...path]` matches `/docs/a/b/c`, giving you `params.path = 'a/b/c'`. Combine with a typed `ParamMatcher` in `src/params/` to validate segments before the route resolves.

Route groups `(group)` organize routes without affecting the URL — perfect for sharing a layout between `/dashboard` and `/settings` without a common path prefix. Parallel routes don't exist natively in SvelteKit; the idiomatic substitute is named layout slots via `@` resets — e.g., `+page@` breaks out of a specific ancestor layout. For intercepted routes (modal patterns), use shallow routing: `goto(url, { state: { modal: true } })` and read `$page.state` to conditionally render a modal overlay instead of navigating away.$escape$,
  $escape$// src/routes/docs/[...path]/+page.server.ts
import type { PageServerLoad } from './$types';

export const load: PageServerLoad = ({ params }) => {
  // params.path = 'getting-started/installation'
  const segments = params.path.split('/');
  return { segments };
};

// src/routes/(app)/settings/+page.svelte — grouped, no URL change
// Shallow routing for modal interception:
// goto('/photo/42', { state: { modal: true } });
// Then in +layout.svelte: if ($page.state.modal) show <Modal />$escape$,
  $escape$typescript$escape$,
