INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd875ab11-6e8d-4fbd-8296-085c198207d1',
  '00000000-0000-0000-0000-000000000001',
  $escape$SvelteKit Web Vitals — Image Optimization, Font Loading, and LCP Tuning$escape$,
  $escape$SvelteKit doesn't ship a built-in `<Image>` component like Next.js, but `@sveltejs/enhanced-img` fills that gap. Add it via `vite-imagetools` integration and use `<enhanced:img>` in your markup — it automatically generates WebP/AVIF variants, injects width/height to prevent layout shift, and produces a `srcset` without manual configuration.

For LCP images, pass `fetchpriority="high"` and skip `loading="lazy"` — the browser needs that resource immediately. Pairing this with a `<link rel="preload">` in your `<svelte:head>` block gives the earliest possible fetch signal.

Font loading is handled cleanly in SvelteKit's `app.html` or via a layout's `<svelte:head>`. Use `font-display: optional` for body fonts to eliminate render-blocking; for brand fonts critical to LCP, `font-display: swap` with a preconnect to your font CDN is the safer tradeoff.

Measure with `$app/environment`'s `browser` guard to run `PerformanceObserver` only client-side, capturing real LCP entries without SSR noise.$escape$,
  $escape$<!-- src/routes/+layout.svelte -->
<svelte:head>
  <link rel="preconnect" href="https://fonts.googleapis.com" />
  <link
    rel="preload"
    as="image"
    href="/hero.avif"
    fetchpriority="high"
  />
</svelte:head>

<!-- Hero component -->
<script>
  import { browser } from '$app/environment';
  import { onMount } from 'svelte';

  onMount(() => {
    if (!browser) return;
    const observer = new PerformanceObserver((list) => {
      for (const entry of list.getEntries()) {
        console.log('LCP candidate:', entry.startTime, entry.element);
      }
    });
    observer.observe({ type: 'largest-contentful-paint', buffered: true });
  });
</script>

<enhanced:img
  src="/hero.png"
  alt="Hero"
  fetchpriority="high"
  loading="eager"
/>$escape$,
  $escape$javascript$escape$,
