INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a429e2b0-68b0-42ca-a180-f4cd0a1c7556',
  '00000000-0000-0000-0000-000000000001',
  $escape$SvelteKit Environment Variables — PUBLIC_ Boundaries, Startup Validation, and Secret Safety$escape$,
  $escape$SvelteKit splits env vars into two enforced namespaces. Variables prefixed with `PUBLIC_` are accessible from `$env/static/public` or `$env/dynamic/public` and can be imported in components, pages, and client-side `+page.ts` files. Everything else lives behind `$env/static/private` or `$env/dynamic/private` — importable only in server-side files like `+page.server.ts`, `+server.ts`, and `hooks.server.ts`. This isn't a convention — SvelteKit's module graph analysis throws a build error if you import a private env module from a shared or client-accessible file.

Validate required vars at startup inside `hooks.server.ts`. It runs once on server boot, surfaces misconfigurations in CI before requests are served, and avoids null-reference crashes buried inside request handlers. Prefer `$env/dynamic/private` over `$env/static/private` when you need runtime flexibility (e.g. container deployments). Never reach for `process.env` directly — SvelteKit's env modules are tree-shaken, statically typed, and enforce the public/private boundary at the compiler level.$escape$,
  $escape$// src/hooks.server.ts
import { env } from '$env/dynamic/private';
import type { Handle } from '@sveltejs/kit';

const REQUIRED = ['DATABASE_URL', 'GROQ_API_KEY', 'CLERK_SECRET_KEY'] as const;

for (const key of REQUIRED) {
  if (!env[key]) {
    throw new Error(`Missing required server env var: ${key}`);
  }
}

export const handle: Handle = ({ event, resolve }) => resolve(event);$escape$,
  $escape$typescript$escape$,
