INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '42a3a204-236e-494d-8454-e10d97962b21',
  '00000000-0000-0000-0000-000000000001',
  $escape$SvelteKit Page Transitions — View Transitions API + Layout Persistence$escape$,
  $escape$SvelteKit's `onNavigate` lifecycle hook is the native integration point for the View Transitions API. Call `document.startViewTransition()` inside it and return a promise — SvelteKit holds the navigation until your promise resolves, giving the browser time to capture the old and new DOM states.

For layout persistence across navigations, the key is understanding that `+layout.svelte` components are never unmounted when child routes change — only the `<slot />` region re-renders. This means elements like sidebars and navbars animate naturally. To persist a specific element's visual identity across routes (e.g., a shared card expanding into a detail view), assign matching `view-transition-name` CSS properties on both pages.

CSS `::view-transition-old` and `::view-transition-new` pseudo-elements let you override the default cross-fade per named element. Pair this with SvelteKit's `preloadData` on hover to ensure data is ready before the transition fires, preventing a flash of loading state mid-animation. For fallback, wrap in `if (document.startViewTransition)` — `onNavigate` still fires in unsupported browsers.$escape$,
  $escape$// src/hooks.client.ts
import { onNavigate } from '$app/navigation';

onNavigate((navigation) => {
  if (!document.startViewTransition) return;

  return new Promise((resolve) => {
    document.startViewTransition(async () => {
      resolve();
      await navigation.complete;
    });
  });
});$escape$,
