INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '366adea9-905a-4b79-95a4-52b12b315f69',
  '00000000-0000-0000-0000-000000000001',
  $escape$SvelteKit Hooks — Edge Middleware for Auth Guards, A/B Testing & Geolocation$escape$,
  $escape$SvelteKit's `handle` hook in `src/hooks.server.ts` is your edge middleware layer — it intercepts every request before any `+page.server.ts` or `+server.ts` runs. Use it to enforce auth guards by inspecting cookies and redirecting unauthenticated users, inject A/B variant flags into `event.locals`, or gate routes by geolocation from request headers.

For auth, read the session cookie via `event.cookies.get()`, validate it, and either `redirect(303, '/login')` or populate `event.locals.user`. Downstream `load` functions and form actions then access `locals.user` without re-validating.

For A/B testing, hash `event.request.headers.get('x-forwarded-for')` or a stable cookie into a bucket, store the variant in `locals.variant`, and render different UI branches in your `+page.svelte`.

Rate limiting fits here too — maintain a `Map` keyed by IP in module scope (or use a KV store like Cloudflare's), check request count, and return a `new Response('Too Many Requests', { status: 429 })` before `resolve(event)` is ever called. Chain multiple concerns with `sequence()` from `@sveltejs/kit/hooks`.$escape$,
  $escape$// src/hooks.server.ts
import { redirect } from '@sveltejs/kit';
import { sequence } from '@sveltejs/kit/hooks';

const auth: Handle = async ({ event, resolve }) => {
  const session = event.cookies.get('session');
  event.locals.user = session ? await validateSession(session) : null;
  if (!event.locals.user && event.url.pathname.startsWith('/dashboard')) {
    redirect(303, '/login');
  }
  return resolve(event);
};

const abTest: Handle = async ({ event, resolve }) => {
  event.locals.variant = (event.cookies.get('uid') ?? '').charCodeAt(0) % 2 === 0 ? 'A' : 'B';
  return resolve(event);
};

export const handle = sequence(auth, abTest);$escape$,
  $escape$typescript$escape$,
